sql:
SELECT name 
FROM pets 
ORDER BY name ASC;

SELECT adopter_name, adoption_status
FROM adoptions
WHERE adoption_status = 'finalized';

SELECT pet_id, next_due_date
FROM vaccinations
WHERE vaccination_type = 'Rabies';

SELECT SUM(duration_minutes) AS total_duration
FROM socialization_activities
WHERE pet_id = 1 AND activity_date BETWEEN '2020-07-01' AND '2020-07-31';

SELECT SUM(hours_logged) AS total_hours
FROM volunteer_hours
WHERE volunteer_id = 1;

SELECT treatment_type, date_administered
FROM medical_treatments
WHERE pet_id = 1;

SELECT note_text
FROM behavioral_notes
WHERE pet_id = 1 AND note_type = 'positive';

SELECT name
FROM pets
ORDER BY name;
